INSERT INTO raw_logs VALUES('8bd847a5-2d6e-487b-b94c-d51fc461bd04','local_default_user','6a096614-43fd-48ed-843d-12f5af06996d','assistant','子供の頃、どんな遊びに夢中になっていましたか？その中で、今のあなたに活きている感覚はありますか？','2026-05-28 06:49:54');
INSERT INTO raw_logs VALUES('7766fefc-6a7a-4bb3-b8de-7ed200bd03c2','local_default_user','6a16e7c4-1dcf-44b2-a08c-6fbd51ef04a8','assistant','あなたの人生で転機になったできごとを教えてください。複数あれば全部話してください。','2026-05-28 07:07:44');
INSERT INTO raw_logs VALUES('21052a74-0955-467d-b4b4-39b009315c2b','local_default_user','6a16e7c4-1dcf-44b2-a08c-6fbd51ef04a8','user',unistr('転機、ですか……いくつかありますね。\u000a\u000aまず会社員時代、キヤノンを辞めたとき。病んでたんですよ、あそこで。「自分が活躍できる場所は自分で作るしかない」って思って飛び出した。あの決断がなければ今の自分はなかったと思います。\u000a\u000a次は会社が潰れて鬱になったとき。あれは本当につらかった。でもそこでSE（ソマティック・エクスペリエンシング）に出会って、「頭じゃなくて体で判断する」という軸ができた。人生で一番大事なことを学んだ時期かもしれない。\u000a\u000aそして2025年の秋、成田空港第2ターミナル。バックパック1つで歩いたとき、なぜかその瞬間だけ妙に体が軽くて、肩が広がるような感覚があって。「あ、これだ」って。それで海外移住を決めました。頭で決めたんじゃなくて、体が決めたんです。'),'2026-05-28 07:08:09');
INSERT INTO raw_logs VALUES('27787b19-f2c4-48bd-8cdb-d27f9a0f1ce1','local_default_user','6a16e7c4-1dcf-44b2-a08c-6fbd51ef04a8','assistant','素晴らしいですね。特に成田空港での「体が決めた」という感覚、とても鮮明に伝わってきます。今はどのようなことに取り組んでいらっしゃいますか？','2026-05-28 07:08:12');
INSERT INTO raw_logs VALUES('8079d067-fb31-45ab-af61-47312380c505','local_default_user','6a16e7c4-1dcf-44b2-a08c-6fbd51ef04a8','user','正直に言うと……今は結構しんどい時期で（笑）。現金が底をつきかけてて、6月以降どうするかって毎日考えてます。Udemyのコースを出し続けてはいるんですけど、それだけじゃ全然足りなくて。ITエージェント経由で仕事も探してるんですが、見てると「またこれか」って胃のあたりが重くなる案件ばかりで。以前みたいな偽装請負に戻るのか……って考えると、体が縮む感じがするんですよね。だから今は、そうじゃない道を必死で模索してる、という感じです。','2026-05-28 07:08:30');
INSERT INTO raw_logs VALUES('0bbccf59-d6a3-497e-ada6-a8eedfdc5577','local_default_user','ffa47805-d640-49b7-b271-6278e8677a93','assistant','あなたの人生で転機になったできごとを教えてください。複数あれば全部話してください。','2026-05-28 07:34:35');
INSERT INTO raw_logs VALUES('43d48fda-81eb-4794-aa3a-6fa24610585a','local_default_user','ffa47805-d640-49b7-b271-6278e8677a93','user',unistr('転機、か…いくつかありますね。\u000a\u000aまずキヤノンを辞めたこと。仕事ができなくて病んでて、「自分の居場所は自分で作るしかない」って思って飛び出した。あれがなければ今の自分はいないです。\u000a\u000a次は会社が潰れて鬱になったとき。4000万の借金を抱えて、2ヶ月ゴロゴロしてても眠れない・食べられないって状態で…あのときにSEっていう身体的なアプローチに出会ったんです。「頭じゃなくて体の感覚で生きる」ってやつ。これは今でも自分の判断軸になってる。\u000a\u000aで、一番最近の転機が、2025年の秋にベトナムに行ったとき。というか正確には成田空港で、バックパック一個持って歩いた瞬間ですね。なぜかその瞬間だけ、体がすーっと軽くなって。「あ、これだ」って。頭で考えたんじゃなくて体が決めた感じ。それで海外移住を決断しました。'),'2026-05-28 07:34:55');
INSERT INTO raw_logs VALUES('8e25a380-46de-4068-9d81-607e32d8dcf0','local_default_user','ffa47805-d640-49b7-b271-6278e8677a93','assistant',unistr('ありがとうございます。キヤノンを辞めたとき、会社が潰れたとき、そして成田空港でのあの瞬間…どれも体で感じた決断だったんですね。特に成田空港で体が軽くなった感覚、とても鮮明に伝わってきました。\u000a\u000a今はベトナムにいらっしゃるんですか？それとも別の場所で、何かに取り組まれている最中でしょうか？'),'2026-05-28 07:35:06');
INSERT INTO raw_logs VALUES('0a4ee960-7bc2-4eb9-b3d1-900020e98a98','local_default_user','ffa47805-d640-49b7-b271-6278e8677a93','user',unistr('今は東南アジアをベースにしながら、仕事探してる最中ですね。ベトナムからスタートして、今は移動しながらって感じで。\u000a\u000a荷物はスーツケース一つとバックパックだけで生活してて…これが想像以上に心地よくて。モノが少ないと頭も軽い気がするんですよね。\u000a\u000a仕事はというと、ITエージェント経由でエンジニアの仕事を探してるんですけど、まあ正直しんどいですよ。いい案件が全然なくて。Udemyのコースも出し続けてるけど、現金が底をつきそうで…6月以降が本当に綱渡りな状況で。\u000a\u000aでも不思議と「焦って変な仕事に飛びつこう」っていう感覚はなくて。体が「それは違う」って言ってるんですよね、ちゃんと。まあ財布は焦ってるんですけど（笑）。'),'2026-05-28 07:35:27');
INSERT INTO raw_logs VALUES('62311dc4-4eca-4810-a85d-78b068fec646','local_default_user','3797274d-4f88-4e10-a323-05d49eadb9b4','assistant','子供の頃、どんな遊びに夢中になっていましたか？その中で、今のあなたに活きている感覚ってありますか？','2026-05-28 07:36:06');
INSERT INTO raw_logs VALUES('636366ba-503c-460e-bef4-a20ab654869b','local_default_user','71dba6b2-982c-4cae-9e4b-400fab601938','assistant','子供の頃、どんなことに夢中になって遊んでいましたか？その時間がどんなふうにあなたの今のエンジニアとしてのスキルや考え方につながっていると思いますか？','2026-05-28 07:36:06');
INSERT INTO raw_logs VALUES('2dc32cf5-3d1b-4772-8d7b-898967c64ad0','local_default_user','71dba6b2-982c-4cae-9e4b-400fab601938','user',unistr('子供の時はプラレールやレゴだねー\u000a何かを作ることにつながっている気がする'),'2026-05-28 07:36:31');
INSERT INTO raw_logs VALUES('0f528b6d-7d48-4298-933f-8854c4aed8c9','local_default_user','71dba6b2-982c-4cae-9e4b-400fab601938','assistant','プラレールやレゴ、いいですね！線路をどうつなげるか、どんな街を作るか、自分で考えて形にしていく楽しさがあったんじゃないかな。今のシステム設計やプロジェクト管理にも、その「組み立てる楽しさ」が生きているように感じます。特に印象に残っている作品や、工夫したエピソードはありますか？','2026-05-28 07:36:36');
INSERT INTO raw_logs VALUES('7eb69bd7-193c-4cc3-963f-9841e819fd32','local_default_user','bd97ae68-4a9a-4b08-bb23-64f6f68d2e64','assistant','あなたの人生で転機になったできごとを教えてください。複数あれば全部話してください。','2026-05-28 07:51:20');
INSERT INTO raw_logs VALUES('0cb651fc-1001-4d62-aba7-12e66e96c66c','local_default_user','bd97ae68-4a9a-4b08-bb23-64f6f68d2e64','user',unistr('転機、いくつかありますね。まず最初は浪人のとき。どこにも属してない状態が、なぜか妙に心地よくて。あの自由さが今の自分の原型な気がします。\u000a\u000a次はキヤノンを辞めたとき。病んでたんですよね、正直。「自分の場所は自分で作るしかない」って思って飛び出した。\u000a\u000aでも一番大きかったのは、会社経営が終わって鬱になったとき。あのとき出会ったSE（ソマティック・エクスペリエンシング）が、体の感覚を判断軸にするっていう今の生き方の土台になっています。\u000a\u000aそして去年の成田空港。バックパック一つ持って第2ターミナルを歩いた瞬間、足から羽が生えたみたいに体が軽くなって。「あ、海外に住もう」って決めたのはその感覚からでした。頭で考えたわけじゃなくて、体が先に動いたんですよね。'),'2026-05-28 07:51:39');
INSERT INTO raw_logs VALUES('3d840598-b361-4bfe-9582-97b659ee6a8a','local_default_user','bd97ae68-4a9a-4b08-bb23-64f6f68d2e64','assistant','浪人、キヤノン退職、経営破綻、成田空港での決断…どれも体感を伴った転機ですね。特に成田の話、足から羽が生えたような感覚、とても鮮明に伝わってきます。今は海外に住まれているんですか？それとも準備中ですか？','2026-05-28 07:51:41');
INSERT INTO raw_logs VALUES('ef2f2766-3604-47bc-902c-00455eebe1cb','local_default_user','bd97ae68-4a9a-4b08-bb23-64f6f68d2e64','user',unistr('もう出てますよ、実際に。2026年2月の末に東京のマンションを引き払って、翌日には東南アジアに飛んだので。荷物はスーツケース1つとバックパックだけで。\u000a\u000a今のところ「軽やかに生きる」ってのを文字通り実践してます。重い荷物もないし、固定費もほぼゼロになって。ただ正直、現実問題として、お金の面はなかなかしんどいですね。仕事も探してますが、なかなか理想通りにはいかなくて。\u000a\u000aでも体の感覚は悪くないんですよ。それだけは確かで。'),'2026-05-28 07:51:53');
