INSERT INTO session_vignettes VALUES('a67bf6bf-8f3b-407f-b23f-9c881daafb07','local_default_user','e37ef1e2-dd8f-4fcf-af8f-39d908649f0e','浪人時代の「肩書きゼロ」の心地よさ','浪人時代（推定2015-2016）','あの「誰にも評価されない感じ」がすごく心地よかったんですよね。あれが自分の原型だと思ってます。','高校を卒業し、大学にも会社にも属さない1年間。周りは焦りや不安を感じる状況だが、本人は「誰にも評価されない」という状態に不思議な心地よさを覚えていた。後に振り返って、あの感覚が自分の原型だと認識している。','評価や肩書きから解放された状態を、不安ではなく心地よさとして感じるという逆説的な感覚が、この人の核にある。',NULL,'private','2026-05-28 08:04:13');
INSERT INTO session_vignettes VALUES('9ad362ee-3976-41c0-9765-621ee0c6f323','local_default_user','e37ef1e2-dd8f-4fcf-af8f-39d908649f0e','成田空港で感じた「足から羽が生えた」瞬間','2025年秋','足から羽が生えたみたいに体が軽くて。「あ、これが自分の生き方だ」ってそのとき決めました。','ベトナム旅行に向けて成田空港でバックパック1個だけを持って歩いた瞬間、身体が驚くほど軽くなる感覚を味わう。その感覚を「自分の生き方」だと確信し、その決断が現在の海外生活の起点となった。','身体感覚を人生の判断基準として信頼し、その感覚に従って大きな決断を下すことができる人物である。',NULL,'private','2026-05-28 08:04:13');
INSERT INTO session_vignettes VALUES('fd41c738-423b-41c3-973a-276b7db1ab63','local_default_user','e37ef1e2-dd8f-4fcf-af8f-39d908649f0e','お金の切迫と体の感覚のせめぎ合い','現在（2025年以降）','体が「嫌だ」って言ってるのはわかってるんですよ。でもお金が切迫してくると、その感覚が遠くなっていく。頭が「とにかく稼がないと」モードになって。これ、ずっと繰り返してるパターンで。','東南アジアでフリーランスとして活動する中、ITエージェント経由の案件を見ると偽装請負の匂いがして首を縦に振れない。体は「嫌だ」と拒否しているが、経済的な切迫が迫るとその感覚が薄れ、頭が「稼がないと」モードに切り替わる。自分でもそのパターンを自覚している。','身体感覚を羅針盤としながらも、経済的プレッシャーがかかるとその羅針盤が狂うことを自覚しており、その葛藤が現在のテーマとなっている。','「体の感覚に従う」という価値観を持ちながら、実際にはお金の切迫によってその感覚を手放しそうになる自分とのギャップを認識している。','private','2026-05-28 08:04:13');
INSERT INTO session_vignettes VALUES('15e5742b-4d46-44bc-aad5-d4e2c127782b','local_default_user','1cd17042-4612-4450-8ea5-84c72c70c83d','自由の迷いと一歩','独立直後','自由な反面、何から手を付けようか迷った','自分のプロダクトが全く売れず困っていたところ、知り合いの社長が小規模なサンプルアプリ開発の仕事をくれた。時間や場所に縛られず結果だけで評価される働き方に「ありがたい」と感じる一方、すべてを自分で決められる自由に戸惑い、何から手をつけるか迷った。','自由を求めながらも、完全な裁量には迷いが生じるという両面性を持っている。',NULL,'private','2026-05-29 03:35:46');
INSERT INTO session_vignettes VALUES('66c8e490-3ada-459b-8abf-b1bd885e618a','local_default_user','1cd17042-4612-4450-8ea5-84c72c70c83d','とりあえずやってみるで掴んだ手応え','独立直後','とりあえずやってみるかな','何から手をつけるか迷いながらも、「とりあえずやってみる」と動き出し、先にプロトタイプを作って顧客に見せて修正するスタイルで進めた。結果的に顧客に満足してもらい、「先に作ってみて見せて修正した方がいい」という学びを得た。','迷いよりも行動を優先する姿勢が、結果と学びを生み出す原動力になっている。',NULL,'private','2026-05-29 03:35:46');
INSERT INTO session_vignettes VALUES('ba3a2dee-86d8-4578-9225-c99442395684','local_default_user','7195ff8b-9099-430f-9b40-9ccdb5ec9bab','AIとの対話から生まれた自己理解ツール','unknown','AIがいい回答をくれないなあと思っていたんだけど、自分自身の情報を上手く与えられていなかったから','AIとの対話で満足いく回答が得られないことに frustration を感じていた。原因を探るうちに、AIに与える自分自身の情報が不足していることに気づき、自分を整理するツールを作ろうと思い立った。','問題の原因を外部（AI）ではなく、自分側の情報不足に帰着させ、それを解決する手段としてソフトウェア開発を選ぶ傾向がある。',NULL,'private','2026-06-01 02:19:31');
INSERT INTO session_vignettes VALUES('ecd3d6b2-c256-4b9e-9872-a35b205db487','local_default_user','34c6e47a-e4de-48ca-ab51-c957bc4af146','自由と自律のための独立','2016-09','雇われるのをやめて自分で会社を作ったことかな？','インタビュアーが絶対に譲れない価値観を尋ねると、ユーザーは「自由、自律」と即答した。その価値観を最も強く感じた出来事として、雇われるのをやめて自分で会社を作った決断を挙げた。2016年9月という具体的な時期も明確に語っている。','自由と自律という価値観を、実際の行動（独立・起業）で体現している。',NULL,'private','2026-06-01 03:20:55');
INSERT INTO session_vignettes VALUES('63451194-3cd6-4037-ade0-810026d6459c','local_default_user','ab031bfa-4122-48c6-b54e-f8a74f5289de','初めての自力マネタイズ、3人の顧客','2018','独立したから初めて自分の力でお金を稼いだときかな？','プログラミング教育のための集客LPを作り、コンバージョンから決済までの流れを自分で構築した。実際に3人のお客さんが来て、初めて自分の力で報酬を得た。','自分で仕組みをゼロから作り、それが実際に機能して成果が出ることに強い達成感を覚えるタイプである。',NULL,'private','2026-06-01 03:29:55');
INSERT INTO session_vignettes VALUES('401e0ef5-2080-4f53-9091-8aefd1aef1c4','local_default_user','2852fb1a-77bc-4f77-8942-874b91bcbcce','縛られる状態を経験し、そこから脱した','unknown','あとは結婚生活もだった！ もちろんどちらも経験していて 離婚したし、社員を維持できなくなって今は1人で返済をしています。','ユーザーは「お金や人間関係に縛られる重い状態」を絶対に避けたいと語った後、自ら結婚生活と経営（借金・人を雇う）の両方を経験し、離婚と社員維持断念という形でそこから脱したことを明かした。現在は一人で返済を続けている。','ユーザーは自らが「縛られる」と定義する状態に実際に入り、そこから抜け出す選択をしている。',NULL,'private','2026-06-01 03:39:57');
